import { SYSTEM_CATEGORY_ID } from "./organization-categories";

// admin が所属するシステム管理組織
export const SYSTEM_ORGANIZATION_ID = "10000000-0000-4000-8000-000000000001";

export const organizationsFixture = [
	{
		categoryId: SYSTEM_CATEGORY_ID,
		email: "",
		name: "システム管理組織",
		organizationId: SYSTEM_ORGANIZATION_ID,
	},
];

import { pgSchema, text, timestamp, uuid } from "drizzle-orm/pg-core";
import { schemaName } from "../pgschema";

// 組織
// category_id は organization_categories への参照だが、
// FK 制約はスキーマ間の依存を避けるため設けない（アプリ層で担保）
export const organizationsTable = pgSchema(schemaName)
	.table("organizations", {
		categoryId: uuid("category_id").notNull(),
		createdAt: timestamp("created_at").defaultNow().notNull(),
		email: text("email").notNull().default(""),
		name: text("name").notNull(),
		organizationId: uuid("organization_id").primaryKey().defaultRandom(),
		updatedAt: timestamp("updated_at")
			.defaultNow()
			.notNull()
			.$onUpdate(() => new Date()),
	})
	.enableRLS();

export type SelectOrganization = typeof organizationsTable.$inferSelect;
export type InsertOrganization = typeof organizationsTable.$inferInsert;

